// // On the falling edge of the clock, the module evaluates the address: if it is less than 2048 (15'h0800), the output is set to zero; if between 2048 and 4096 (15'h1000), the output corresponds directly to the lower 12 bits of the address; for addresses equal to or greater than 4096, the output is derived from the upper bits of the address, specifically the bits from address[14:3].
module top_module(
    input [14:0] address,
    input clock,
    output reg [11:0] q
);always @(posedge clock) begin
    if(address < 15'h0800) begin
        q <= 12'h000;
    end else if(address < 15'h1000) begin
        q <= address[11:0];
    end else begin
        q <= address[14:3];
    end
end

endmodule
